mapper.update:





update ac_employee_attendance set enabled_flag = 0,
    update_by        = #{updateBy,jdbcType=BIGINT},
    update_time      = #{updateTime,jdbcType=TIMESTAMP}
where id = #{id,jdbcType=BIGINT}

mapper.select:
select al.*,aea.* from (select
from ac_calendar_header ach,ac_calendar_line acl where ach.default_flag = 1 and ach.id = acl.calendar_header_id
and datediff(month, acl.now_date, #{criteria.month, jdbcType=DATE}) = 0
and (acl.now_date <= #{criteria.dateTo, jdbcType=DATE} AND acl.now_date >= #{criteria.dateFrom, jdbcType=DATE})
) al left join (select
,
from ac_employee_attendance aea, pm_employee pe where 1 = 1 and aea.employee_id = pe.id and pe.enabled_flag = 1 and pe.leave_flag = 0 and pe.workshop_attendance_flag = 1
and exists (SELECT 1 FROM pm_employee_job pej_t WHERE pej_t.employee_id = pe.id AND pej_t.enabled_flag = 1 AND pej_t.dept_id IN
#{item, jdbcType=BIGINT}
)
and aea.enabled_flag = #{criteria.enabled, jdbcType=BIT}
) aea on al.now_date = aea.aea_regimea_date order by al.now_date

select temp.*, fd_dept.dept_name as pe_dept_name,fd_department.dept_name AS pe_department, fd_team.dept_name AS pe_team from ( SELECT pe.id pe_id, pe.work_card pe_work_card, pe.name pe_name, ISNULL (aea.regimea_date, acl.now_date) AS regimea_date, ISNULL (aea.id, -1) id, aea.employee_id, aea.first_time_from, aea.first_time_to, aea.extend1_time_flag, aea.second_time_from, aea.second_time_to, aea.extend2_time_flag, aea.third_time_from, aea.third_time_to, aea.extend3_time_flag, aea.attribute1, aea.attribute2, aea.attribute3, aea.enabled_flag, aea.create_by, aea.create_time, aea.update_by, aea.update_time, aea.rest_day_flag FROM pm_employee pe JOIN ac_calendar_header ach ON ach.default_flag = 1 JOIN ac_calendar_line acl ON ach.id = acl.calendar_header_id LEFT OUTER JOIN ac_employee_attendance aea ON aea.employee_id = pe.id AND aea.regimea_date = acl.now_date
AND aea.enabled_flag = #{criteria.enabled, jdbcType=BIT}
WHERE pe.enabled_flag = 1 AND pe.leave_flag = 0 AND pe.workshop_attendance_flag = 1 AND pe.work_attendance_flag = 1
AND pe.pe_id = #{criteria.employeeId, jdbcType=BIGINT}
AND pe.id IN
#{item, jdbcType=BIGINT}
AND pe.work_card like #{criteria.workCard, jdbcType=VARCHAR}
AND pe.name like #{criteria.name, jdbcType=VARCHAR}
AND EXISTS (SELECT 1 FROM pm_employee_job pej_t WHERE pej_t.employee_id = pe.id AND pej_t.enabled_flag = 1 AND pej_t.dept_id IN
#{item, jdbcType=BIGINT}
)
AND (acl.now_date >= #{criteria.dateFrom, jdbcType=DATE} AND acl.now_date <= #{criteria.dateTo, jdbcType=DATE}) ) temp,pm_employee_job pej
outer apply f_get_dept_parent_by_level(pej.dept_id,'部','部门','-') fd_dept OUTER apply f_get_dept_parent_by_level ( pej.dept_id, '科室', '-', '-' ) fd_department OUTER apply f_get_dept_parent_by_level ( pej.dept_id, '班组', '-', '-' ) fd_team where pej.employee_id = temp.pe_id and pej.enabled_flag = 1 and pej.job_main_flag = 1 order by temp.pe_id,regimea_date

select pe.id, pe.name, pe.work_card, isnull((select fdt.dept_name from fnd_dept fd join fnd_dept fdt on fd.ext_dept_id = fdt.id and fd.id = pejs.dept_id where fd.enabled_flag = 1 and fd.deleted_flag = 0 and fdt.enabled_flag = 1 and fdt.deleted_flag = 0), '') as dept_name, isnull((select fdt.dept_name from fnd_dept fd join fnd_dept fdt on fd.ext_department_id = fdt.id and fd.id = pejs.dept_id where fd.enabled_flag = 1 and fd.deleted_flag = 0 and fdt.enabled_flag = 1 and fdt.deleted_flag = 0), '') as department, isnull((select fdt.dept_name from fnd_dept fd join fnd_dept fdt on fd.ext_team_id = fdt.id and fd.id = pejs.dept_id where fd.enabled_flag = 1 and fd.deleted_flag = 0 and fdt.enabled_flag = 1 and fdt.deleted_flag = 0), '') as team from pm_employee pe join pm_employee_job pejs on pe.id = pejs.employee_id where pe.workshop_attendance_flag = 1 and pe.work_attendance_flag = 1 and pe.enabled_flag =1 and pejs.enabled_flag = 1 and pe.leave_flag = 0 and pejs.dept_id in
#{item, jdbcType=BIGINT}
and not EXISTS ( select 1 from ac_employee_attendance aea where aea.regimea_date = CONVERT(varchar(100), dateAdd(dd, 1, getDate()), 23) and pe.id = aea.employee_id )
